import{_ as a,o as s,c as t,a as i}from"./chunks/framework.8tiMeCK-.js";const u=JSON.parse('{"title":"9.9  Ftrace 实战：从栈溢出监控到 Android 排毒","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch09_9.md","filePath":"notes/linux_kernel_debugging/ch09_9.md","lastUpdated":null}'),r={name:"notes/linux_kernel_debugging/ch09_9.md"};function n(o,e,l,c,p,d){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="_9-9-ftrace-实战-从栈溢出监控到-android-排毒" tabindex="-1">9.9 Ftrace 实战：从栈溢出监控到 Android 排毒 <a class="header-anchor" href="#_9-9-ftrace-实战-从栈溢出监控到-android-排毒" aria-label="Permalink to &quot;9.9  Ftrace 实战：从栈溢出监控到 Android 排毒&quot;">​</a></h1><p>好了，Instances 的话题先告一段落。</p><p>有了这么多工具，具体怎么用？Ftrace 就像一把瑞士军刀，功能多到你可能会拿着刀不知道该往哪剁。本节我们要看几个真实的「杀猪」现场——不是真的杀猪，是杀 Bug。</p><p>我们先看一个隐蔽但致命的内核问题：栈溢出。</p><hr><h2 id="监控内核栈使用情况——ftrace-的「测谎仪」" tabindex="-1">监控内核栈使用情况——Ftrace 的「测谎仪」 <a class="header-anchor" href="#监控内核栈使用情况——ftrace-的「测谎仪」" aria-label="Permalink to &quot;监控内核栈使用情况——Ftrace 的「测谎仪」&quot;">​</a></h2><p>你可能知道，每个活着的线程都有两套栈：一套用户态栈，一套内核态栈。</p><p>用户态栈很大，也很「软」，它是动态增长的。在普通的 Linux 发行版上，它的上限（<code>RLIMIT_STACK</code>）通常是 8 MB。如果你不够用，内核会自动帮你扩容，直到撑爆这个限制。</p><p>但内核态栈完全是另一套生物。</p><p>它是固定的，硬的，而且非常小。</p><ul><li>在 32 位系统上，通常只有 <strong>8 KB</strong>。</li><li>在 64 位系统上，通常是 <strong>16 KB</strong>。</li></ul><p>这就带来一个严重的后果：<strong>溢出</strong>。如果你的内核代码递归太深，或者局部变量开得太大，内核栈就会溢出。这不是什么「抛个异常」那么简单，这通常意味着系统立刻锁死，或者直接 Kernel Panic。这是那种会让你在深夜三点盯着控制台怀疑人生的 Bug。</p><blockquote><p>⚠️ <strong>配置提示</strong></p><p>有两个内核选项能稍微缓解这种痛苦：</p><ul><li><code>CONFIG_VMAP_STACK</code>：开启后，内核栈会从 <code>vmalloc</code> 区域分配。这允许内核设置一个「守卫页」，一旦栈溢出触碰到守卫页，内核会触发 Oops 并优雅地杀掉进程，而不是直接把整台机器带走。</li><li><code>CONFIG_THREAD_INFO_IN_TASK</code>：这能进一步减轻栈溢出带来的连锁反应。</li></ul><p>如果你在编译内核，记得把它们勾上。</p></blockquote><p>正因为内核栈这么脆弱，<strong>监控它在运行时用了多少</strong>，就成了一个非常有价值的调试手段。Ftrace 自带了一个专门的工具做这件事——<strong>Stack Tracer（栈跟踪器）</strong>。</p><p>要启用它，确保你的内核配置里有 <code>CONFIG_STACK_TRACER=y</code>（通常默认是开的）。它不由 <code>tracefs</code> 直接控制，而是通过 <code>/proc</code> 伪文件 <code>/proc/sys/kernel/stack_tracer_enabled</code> 来开关，默认是关的。</p><p>让我们来一次实战演练。我们将开启 ftrace 的栈跟踪器，跑一轮采样，看看哪些内核函数是「吃栈怪兽」（注意，这需要 root 权限）：</p><h3 id="第一步——开启栈跟踪器" tabindex="-1">第一步——开启栈跟踪器 <a class="header-anchor" href="#第一步——开启栈跟踪器" aria-label="Permalink to &quot;第一步——开启栈跟踪器&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/sys/kernel/stack_tracer_enabled</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="第二步——跑一轮采样" tabindex="-1">第二步——跑一轮采样 <a class="header-anchor" href="#第二步——跑一轮采样" aria-label="Permalink to &quot;第二步——跑一轮采样&quot;">​</a></h3><p>我们需要一个脚本来辅助。我写了一个很简单的脚本 <code>ch9/ftrace/ftrc_1s.sh</code>，它会开启 ftrace 并记录内核在 1 秒钟内的活动。在这个窗口期内，我们会尽可能触发栈的深度使用。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/kernel/tracing</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/ch9/ftrace/ftrc_1s.sh</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="第三步——查看最大栈深度和细节" tabindex="-1">第三步——查看最大栈深度和细节 <a class="header-anchor" href="#第三步——查看最大栈深度和细节" aria-label="Permalink to &quot;第三步——查看最大栈深度和细节&quot;">​</a></h3><p>现在，数据已经记下来了。我们主要关心两个文件：</p><ul><li><code>stack_max_size</code>：自系统启动以来（或者自上一次清空以来）观测到的最大栈使用量。</li><li><code>stack_trace</code>：产生这个最大深度的那个时刻的调用栈详情。</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stack_max_size</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stack_trace</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>下面的截图展示了一次运行的结果。在这个例子里，内核栈的最大使用量超过了 4000 字节（接近 4KB，这意味着在 32 位系统上一半的栈空间已经没了）。</p><blockquote><p><em>（此处插入 Figure 9.19 的截图描述：显示 stack_max_size 为 4160 字节，以及其下方的详细函数调用栈）</em></p></blockquote><p>如果你看到这个数字逼近了 8 KB（32 位）或 16 KB（64 位），你的心跳应该加速一下。那意味着离崩溃只有几步之遥了。</p><p>关于 Stack Tracer 的更多细节，可以翻看官方内核文档：<code>Documentation/trace/ftrace.html</code>。</p><hr><h2 id="android-是怎么用-ftrace-给系统排毒的" tabindex="-1">Android 是怎么用 Ftrace 给系统排毒的 <a class="header-anchor" href="#android-是怎么用-ftrace-给系统排毒的" aria-label="Permalink to &quot;Android 是怎么用 Ftrace 给系统排毒的&quot;">​</a></h2><p>工具好不好用，要看战场在哪里。</p><p>Android Open Source Project (AOSP) 不仅是用 Ftrace，简直是把它当成了核武器。在 Android 内部开发中，他们其实是在 Ftrace 之上包了一层壳，但也允许直接用。</p><p>AOSP 的官方文档里有一段话非常硬核，我建议你背下来：</p><blockquote><p>&quot;However, every single difficult performance bug in 2015 and 2016 was ultimately root-caused using dynamic ftrace.&quot;</p><p>「然而，2015 和 2016 年每一个困难的性能 Bug，最终都是靠 dynamic ftrace 找到了根本原因。」</p></blockquote><p>这口气不小，但如果你看过 Android 设备的复杂性，就会明白这并不是在吹牛。</p><p>文档里特别提到了 Ftrace 的几个杀手级应用场景：</p><ol><li><p><strong>调试不可中断睡眠（Uninterruptible Sleep）</strong> 为什么难调？因为进程睡了，日志可能也就停了。但用 Ftrace 的 <code>function_graph</code> 或 <code>function</code> tracer 配合过滤器，你可以<strong>每一次</strong>代码进入 <code>uninterruptible_sleep</code> 函数时都抓一个内核栈快照。这就像是给昏迷的病人每分钟做一次心电图。</p></li><li><p><strong>确认驱动「霸占」CPU 的时间</strong> 驱动程序可能会为了「原子性」而长时间关中断或关抢占。这在单线程代码里看似安全，但在多核系统里是灾难。</p><p>还记得上一节我们提到的那些「延迟跟踪器」吗？</p><ul><li><code>irqsoff</code></li><li><code>preemptoff</code></li><li><code>preemptirqsoff</code></li></ul><p>AOSP 文档直接点名：这些工具主要用于<strong>证实</strong>驱动程序是不是把中断或抢占关得太久了。</p></li></ol><h3 id="真实案例-拍照后的卡顿" tabindex="-1">真实案例：拍照后的卡顿 <a class="header-anchor" href="#真实案例-拍照后的卡顿" aria-label="Permalink to &quot;真实案例：拍照后的卡顿&quot;">​</a></h3><p>文档里举了一个真实的例子：一台 Pixel XL 手机。 <strong>现象</strong>：拍完一张 HDR 照片后，立刻旋转取景框，界面出现了明显的卡顿（Jank）。 <strong>手段</strong>：就是靠 Ftrace 抓出来的。通过 trace 他们发现，某个关键路径被某个长耗时操作堵住了，导致了响应延迟。 （详见：<a href="https://source.android.com/devices/tech/debug/ftrace%EF%BC%89" target="_blank" rel="noreferrer">https://source.android.com/devices/tech/debug/ftrace）</a></p><p>不仅是这个例子，AOSP 文档还总结了一些常见模式：</p><ul><li><strong>驱动失职</strong>：驱动程序把硬件中断（IRQ）或抢占关了太久，导致系统响应变慢。</li><li><strong>软中断（Softirq）过长</strong>：软中断会禁止内核抢占。如果处理软中断的时间太长，别的任务就切不进来，系统感觉就像死机了一样。</li></ul><p>这东西非常有趣。如果你在写嵌入式 Linux 或者 Android 驱动，不懂 Ftrace，基本上就是在闭眼开车。</p><hr><h2 id="netflix-的云端实战-预告片" tabindex="-1">Netflix 的云端实战：预告片 <a class="header-anchor" href="#netflix-的云端实战-预告片" aria-label="Permalink to &quot;Netflix 的云端实战：预告片&quot;">​</a></h2><p>这种「穷追猛打」的精神不仅限于手机界。</p><p>在云端，Ftrace 也是定海神针。这里再预告一个更精彩的真实案例：使用 <strong>perf-tools</strong> 脚本（也就是我们前面提到的、Brendan Gregg 写的那套基于 Ftrace 的前端工具集）来调试 Netflix Linux 实例上的数据库磁盘 I/O 问题。</p><p>我们会在后面专门有一节（&quot;Investigating a database disk I/O issue on Netflix cloud instances with perf-tools&quot;）来讲这个。</p><p>那里的战场从手机变成了云服务器，武器从原始 Ftrace 变成了更友好的脚本，但核心逻辑是一样的：<strong>看见不可见之物</strong>。</p>`,49)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
